import { startServer } from "./server.js";
const socketPath = process.argv[2] ?? undefined;
const pidPath = process.argv[3] ?? undefined;
// "" means absent (prod singleton passes no meta/worktree).
const metaPath = process.argv[4] || undefined;
const worktreeRoot = process.argv[5] || undefined;
startServer(socketPath, pidPath, metaPath, worktreeRoot);
